import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.firestore.SetOptions
import com.lksnext.ParkingMMartinez.model.NotificationItem
import com.onesignal.OneSignal
import com.onesignal.user.subscriptions.IPushSubscriptionObserver
import com.onesignal.user.subscriptions.PushSubscriptionChangedState
import kotlinx.coroutines.CoroutineDispatcher
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import org.json.JSONObject
import org.json.JSONArray
import java.io.BufferedReader
import java.io.InputStreamReader
import java.io.OutputStreamWriter
import java.net.HttpURLConnection
import java.net.URL

class FirebaseNotificationRepository(
    private val ioDispatcher: CoroutineDispatcher = Dispatchers.IO
) : NotificationRepository {

    private val firestore = FirebaseFirestore.getInstance()
    private val collection = firestore.collection("notifications")

    override fun saveNotification(notification: NotificationItem) {
        val docRef = collection.document()
        val finalNotification = notification.copy(id = docRef.id)
        docRef.set(finalNotification)
    }

    override fun getNotificationsFlow(userId: String, onUpdate: (List<NotificationItem>) -> Unit) {
        collection
            .whereEqualTo("userId", userId)
            .addSnapshotListener { snapshot, error ->
                if (error != null || snapshot == null) {
                    onUpdate(emptyList())
                    return@addSnapshotListener
                }
                val items = snapshot.toObjects(NotificationItem::class.java)
                val sortedItems = items.sortedByDescending { it.timestamp?.time ?: 0L }
                onUpdate(sortedItems)
            }
    }

    override fun markAllAsRead(userId: String) {
        collection
            .whereEqualTo("userId", userId)
            .whereEqualTo("isRead", false)
            .get()
            .addOnSuccessListener { snapshot ->
                val batch = firestore.batch()
                for (doc in snapshot.documents) {
                    batch.update(doc.reference, "isRead", true)
                }
                batch.commit()
            }
    }

    override fun deleteNotification(notificationId: String) {
        collection.document(notificationId).delete()
    }

    override fun deleteAllNotifications(userId: String) {
        collection.whereEqualTo("userId", userId).get()
            .addOnSuccessListener { snapshot ->
                val batch = firestore.batch()
                for (doc in snapshot.documents) {
                    batch.delete(doc.reference)
                }
                batch.commit()
            }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // BUG FIX 1: Observer pattern for linkDeviceWithUser
    //
    // The previous implementation read OneSignal.User.pushSubscription.id
    // synchronously at login time. On the first run (or after a cold start)
    // the OneSignal SDK hasn't finished registering with its servers yet, so
    // the ID is null → nothing was ever written to Firestore →
    // sendBroadcastNotification always found an empty list and returned early.
    //
    // Fix: try immediately; if null, register an IPushSubscriptionObserver so
    // the ID is persisted as soon as the SDK assigns one.
    // ─────────────────────────────────────────────────────────────────────────
    override fun linkDeviceWithUser(userId: String) {
        val immediateId = OneSignal.User.pushSubscription.id

        if (!immediateId.isNullOrEmpty()) {
            // ID already available — save right away
            saveOneSignalIdToFirestore(userId, immediateId)
            return
        }

        // SDK hasn't assigned an ID yet — observe and save the moment it does
        Log.d("OneSignal_Firestore", "Subscription ID no disponible aún para user=$userId. Registrando observador...")

        val observer = object : IPushSubscriptionObserver {
            override fun onPushSubscriptionChange(state: PushSubscriptionChangedState) {
                val newId = state.current.id
                if (!newId.isNullOrEmpty()) {
                    OneSignal.User.pushSubscription.removeObserver(this)
                    saveOneSignalIdToFirestore(userId, newId)
                }
            }
        }
        OneSignal.User.pushSubscription.addObserver(observer)
    }

    /** Persists [onesignalId] into the user's Firestore document using merge. */
    private fun saveOneSignalIdToFirestore(userId: String, onesignalId: String) {
        Log.d("OneSignal_Firestore", "Guardando onesignal_id='$onesignalId' para user='$userId'…")
        firestore.collection("users").document(userId)
            .set(mapOf("onesignal_id" to onesignalId), SetOptions.merge())
            .addOnSuccessListener {
                Log.d("OneSignal_Firestore", "✅ onesignal_id guardado para user='$userId'")
            }
            .addOnFailureListener { e ->
                Log.e("OneSignal_Firestore", "❌ Error guardando onesignal_id para user='$userId'", e)
            }
    }

    override fun sendPushNotification(
        context: Context,
        targetUserId: String,
        title: String,
        message: String
    ) {
        firestore.collection("users").document(targetUserId).get()
            .addOnSuccessListener { document ->
                val targetOneSignalId = document.getString("onesignal_id")

                if (!targetOneSignalId.isNullOrEmpty()) {
                    CoroutineScope(ioDispatcher).launch {
                        try {
                            val appId   = resolveResString(context, "onesignal_app_id_secret")
                            val restKey = resolveResString(context, "onesignal_rest_api_key_secret")
                            if (appId.isEmpty()) {
                                Log.e("OneSignal_Push", "App ID vacío — push cancelado.")
                                return@launch
                            }

                            val jsonBody = JSONObject().apply {
                                put("app_id", appId)
                                put("include_subscription_ids", JSONArray().put(targetOneSignalId))
                                put("headings", JSONObject().put("en", title))
                                put("contents", JSONObject().put("en", message))
                                put("android_sound", "notification")
                                put("priority", 10)
                            }

                            val code = postToOneSignal(jsonBody, restKey)
                            Log.d("OneSignal_Push", "Resultado envío: código $code")

                        } catch (e: Exception) {
                            Log.e("OneSignal_Push", "Error crítico al enviar push", e)
                        }
                    }
                }
            }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // BUG FIX 2: Authorization header + verbose diagnostic logging
    //
    // The OneSignal REST API /api/v1/notifications requires:
    //   Authorization: Basic <REST_API_KEY>
    // Without it the server returns HTTP 400 and rejects the payload.
    //
    // The REST API Key is read from the string resource
    // "onesignal_rest_api_key_secret" (injected via Gradle resValue — see
    // build.gradle.kts). Add  onesignal.rest.api.key=YOUR_KEY  to
    // gradle.properties (never commit that file).
    // ─────────────────────────────────────────────────────────────────────────
    override fun sendBroadcastNotification(context: Context, title: String, message: String) {
        Log.d("OneSignal_Broadcast", "sendBroadcastNotification() llamado. Consultando Firestore…")

        firestore.collection("users")
            .get()
            .addOnSuccessListener { snapshot ->
                Log.d("OneSignal_Broadcast", "Firestore devolvió ${snapshot.size()} documentos de usuarios.")

                // Collect (userId, onesignalId) pairs — we need userId for Firestore
                // notification records and onesignalId for the push payload.
                val usersWithSubscription = snapshot.documents.mapNotNull { doc ->
                    val onesignalId = doc.getString("onesignal_id")
                    if (!onesignalId.isNullOrBlank()) doc.id to onesignalId else null
                }

                Log.d("OneSignal_Broadcast", "Usuarios con onesignal_id válido: ${usersWithSubscription.size}")

                if (usersWithSubscription.isEmpty()) {
                    Log.e(
                        "OneSignal_Broadcast",
                        "❌ Ningún usuario tiene onesignal_id en Firestore. " +
                        "Verifica que linkDeviceWithUser() se ejecutó correctamente y que " +
                        "el campo 'onesignal_id' existe en la colección 'users'."
                    )
                    return@addOnSuccessListener
                }

                val allSubscriptionIds = usersWithSubscription.map { it.second }
                val allUserIds         = usersWithSubscription.map { it.first }

                CoroutineScope(ioDispatcher).launch {
                    try {
                        val appId   = resolveResString(context, "onesignal_app_id_secret")
                        val restKey = resolveResString(context, "onesignal_rest_api_key_secret")

                        if (appId.isEmpty()) {
                            Log.e("OneSignal_Broadcast", "❌ App ID vacío — broadcast cancelado.")
                            return@launch
                        }
                        if (restKey.isEmpty()) {
                            Log.e(
                                "OneSignal_Broadcast",
                                "❌ REST API Key vacía — el servidor rechazará la petición. " +
                                "Añade  onesignal.rest.api.key=TU_CLAVE  a gradle.properties " +
                                "y asegúrate de que build.gradle.kts genera 'onesignal_rest_api_key_secret'."
                            )
                        }

                        val jsonHeadings = JSONObject().put("en", title)
                        val jsonContents = JSONObject().put("en", message)

                        var atLeastOneChunkSucceeded = false

                        allSubscriptionIds.chunked(2_000).forEachIndexed { chunkIndex, chunk ->
                            try {
                                val idsArray = JSONArray().apply { chunk.forEach { put(it) } }

                                val jsonBody = JSONObject().apply {
                                    put("app_id", appId)
                                    put("include_subscription_ids", idsArray)
                                    put("headings", jsonHeadings)
                                    put("contents", jsonContents)
                                    put("android_sound", "notification")
                                    put("priority", 10)
                                }

                                Log.d("OneSignal_Broadcast", "Enviando chunk $chunkIndex (${chunk.size} IDs)…")
                                val code = postToOneSignal(jsonBody, restKey)
                                Log.d("OneSignal_Broadcast", "Chunk $chunkIndex → HTTP $code")

                                if (code !in 200..299) {
                                    Log.e("OneSignal_Broadcast", "❌ Chunk $chunkIndex rechazado (HTTP $code). Revisa el REST API Key y el App ID.")
                                } else {
                                    Log.d("OneSignal_Broadcast", "✅ Chunk $chunkIndex enviado con éxito.")
                                    atLeastOneChunkSucceeded = true
                                }

                            } catch (chunkEx: Exception) {
                                Log.e("OneSignal_Broadcast", "Error en chunk $chunkIndex", chunkEx)
                            }
                        }

                        // ── FEATURE 3: persist notification in Firestore for each user ──
                        // Only save if at least one chunk was delivered successfully so we
                        // don't flood the notification screen with alerts nobody received.
                        if (atLeastOneChunkSucceeded) {
                            allUserIds.forEach { userId ->
                                val notif = NotificationItem(
                                    userId  = userId,
                                    title   = title,
                                    body    = message,
                                    isRead  = false
                                )
                                saveNotification(notif)
                            }
                            Log.d(
                                "OneSignal_Broadcast",
                                "✅ NotificationItem guardada en Firestore para ${allUserIds.size} usuarios."
                            )
                        }

                    } catch (e: Exception) {
                        Log.e("OneSignal_Broadcast", "Error crítico en broadcast HTTP", e)
                    }
                }
            }
            .addOnFailureListener { e ->
                Log.e("OneSignal_Broadcast", "Error al consultar Firestore", e)
            }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Helpers
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * Reads a string resource injected via Gradle [resValue].
     * Returns an empty string if the resource does not exist.
     */
    private fun resolveResString(context: Context, resName: String): String {
        val id = context.resources.getIdentifier(resName, "string", context.packageName)
        return if (id != 0) context.getString(id) else ""
    }

    /**
     * Executes an HTTP POST to the OneSignal v1 notifications endpoint.
     * Adds the Authorization header only when [restApiKey] is non-empty.
     *
     * @return HTTP response code.
     */
    private fun postToOneSignal(body: JSONObject, restApiKey: String): Int {
        val url  = URL("https://onesignal.com/api/v1/notifications")
        val conn = url.openConnection() as HttpURLConnection
        return try {
            conn.requestMethod = "POST"
            conn.setRequestProperty("Content-Type", "application/json; charset=UTF-8")
            if (restApiKey.isNotEmpty()) {
                conn.setRequestProperty("Authorization", "Basic $restApiKey")
            }
            conn.doOutput = true

            OutputStreamWriter(conn.outputStream).use { writer ->
                writer.write(body.toString())
                writer.flush()
            }

            val code = conn.responseCode

            // Log the error body to understand API rejections
            if (code !in 200..299) {
                val errorStream = conn.errorStream ?: conn.inputStream
                val errorBody = BufferedReader(InputStreamReader(errorStream)).use { it.readText() }
                Log.e("OneSignal_HTTP", "Respuesta de error (HTTP $code): $errorBody")
            }

            code
        } finally {
            conn.disconnect()
        }
    }
}

package com.lksnext.ParkingMMartinez.data.repository

import android.content.Context
import android.content.res.Configuration
import android.util.Log
import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.firestore.QuerySnapshot
import com.google.firebase.firestore.SetOptions
import com.lksnext.ParkingMMartinez.model.NotificationItem
import com.onesignal.OneSignal
import com.onesignal.user.subscriptions.IPushSubscriptionObserver
import com.onesignal.user.subscriptions.PushSubscriptionChangedState
import kotlinx.coroutines.CoroutineDispatcher
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import org.json.JSONArray
import org.json.JSONObject
import java.io.BufferedReader
import java.io.InputStreamReader
import java.io.OutputStreamWriter
import java.net.HttpURLConnection
import java.net.URL
import java.text.SimpleDateFormat
import java.util.Locale

class FirebaseNotificationRepository(
    private val ioDispatcher: CoroutineDispatcher = Dispatchers.IO
) : NotificationRepository {

    // ── Supported locale codes for multi-language push payloads ──────────────
    private val SUPPORTED_LOCALES = listOf("en", "es", "de", "fr", "it", "pt", "eu")
    private val ISO_DATE_PATTERN  = Regex("^\\d{4}-\\d{2}-\\d{2}$")

    /** Lightweight projection of a Firestore user document. */
    private data class UserEntry(
        val userId: String,
        val onesignalId: String,
        val languageCode: String
    )

    private val firestore  = FirebaseFirestore.getInstance()
    private val collection = firestore.collection("notifications")

    // ── Standard notification CRUD ────────────────────────────────────────────

    override fun saveNotification(notification: NotificationItem) {
        val docRef = collection.document()
        docRef.set(notification.copy(id = docRef.id))
    }

    override fun getNotificationsFlow(userId: String, onUpdate: (List<NotificationItem>) -> Unit) {
        collection.whereEqualTo("userId", userId)
            .addSnapshotListener { snapshot, error ->
                if (error != null || snapshot == null) { onUpdate(emptyList()); return@addSnapshotListener }
                onUpdate(snapshot.toObjects(NotificationItem::class.java)
                    .sortedByDescending { it.timestamp?.time ?: 0L })
            }
    }

    override fun markAllAsRead(userId: String) {
        collection.whereEqualTo("userId", userId).whereEqualTo("isRead", false)
            .get()
            .addOnSuccessListener { snapshot ->
                val batch = firestore.batch()
                snapshot.documents.forEach { batch.update(it.reference, "isRead", true) }
                batch.commit()
            }
    }

    override fun deleteNotification(notificationId: String) {
        collection.document(notificationId).delete()
    }

    override fun deleteAllNotifications(userId: String) {
        collection.whereEqualTo("userId", userId).get()
            .addOnSuccessListener { snapshot ->
                val batch = firestore.batch()
                snapshot.documents.forEach { batch.delete(it.reference) }
                batch.commit()
            }
    }

    // ── Device ↔ user wiring ─────────────────────────────────────────────────

    override fun linkDeviceWithUser(userId: String) {
        val immediateId = OneSignal.User.pushSubscription.id
        if (!immediateId.isNullOrEmpty()) {
            saveOneSignalIdToFirestore(userId, immediateId)
            return
        }
        Log.d(TAG_FIRESTORE, "Subscription ID no disponible aún para user=$userId. Registrando observador...")
        val observer = object : IPushSubscriptionObserver {
            override fun onPushSubscriptionChange(state: PushSubscriptionChangedState) {
                val newId = state.current.id
                if (!newId.isNullOrEmpty()) {
                    OneSignal.User.pushSubscription.removeObserver(this)
                    saveOneSignalIdToFirestore(userId, newId)
                }
            }
        }
        OneSignal.User.pushSubscription.addObserver(observer)
    }

    private fun saveOneSignalIdToFirestore(userId: String, onesignalId: String) {
        Log.d(TAG_FIRESTORE, "Guardando onesignal_id='$onesignalId' para user='$userId'…")
        firestore.collection("users").document(userId)
            .set(mapOf("onesignal_id" to onesignalId), SetOptions.merge())
            .addOnSuccessListener { Log.d(TAG_FIRESTORE, "✅ onesignal_id guardado para user='$userId'") }
            .addOnFailureListener { e -> Log.e(TAG_FIRESTORE, "❌ Error guardando onesignal_id", e) }
    }

    // ── Single-user push ──────────────────────────────────────────────────────

    override fun sendPushNotification(context: Context, targetUserId: String, title: String, message: String) {
        firestore.collection("users").document(targetUserId).get()
            .addOnSuccessListener { document ->
                val targetId = document.getString("onesignal_id") ?: return@addOnSuccessListener
                if (targetId.isBlank()) return@addOnSuccessListener
                CoroutineScope(ioDispatcher).launch {
                    try {
                        val appId   = resolveResString(context, "onesignal_app_id_secret")
                        val restKey = resolveResString(context, "onesignal_rest_api_key_secret")
                        if (appId.isEmpty()) { Log.e(TAG_PUSH, "App ID vacío — push cancelado."); return@launch }
                        val body = JSONObject().apply {
                            put("app_id", appId)
                            put("include_subscription_ids", JSONArray().put(targetId))
                            put("headings", JSONObject().put("en", title))
                            put("contents", JSONObject().put("en", message))
                            put("android_sound", "notification")
                            put("priority", 10)
                        }
                        val code = postToOneSignal(body, restKey)
                        Log.d(TAG_PUSH, "Resultado envío: código $code")
                    } catch (e: Exception) {
                        Log.e(TAG_PUSH, "Error crítico al enviar push", e)
                    }
                }
            }
    }

    // ── Broadcast push (Issues 1 + 3) ────────────────────────────────────────
    //
    // Refactored into small private methods (< 15 cognitive complexity each) and
    // extended with:
    //   • Multi-language OneSignal payload — each device receives the text in its
    //     language (set via OneSignal.User.setLanguage when the user changes locale).
    //   • Per-user Firestore NotificationItem saved in the user's stored language.
    //   • ISO-8601 date args ("yyyy-MM-dd") are formatted per locale automatically.

    override fun sendBroadcastNotification(
        context: Context,
        titleResId: Int,
        bodyResId: Int,
        bodyFormatArgs: List<String>
    ) {
        Log.d(TAG_BROADCAST, "sendBroadcastNotification() llamado. Consultando Firestore…")
        firestore.collection("users").get()
            .addOnSuccessListener { handleBroadcastUsers(context, it, titleResId, bodyResId, bodyFormatArgs) }
            .addOnFailureListener { e -> Log.e(TAG_BROADCAST, "Error al consultar Firestore", e) }
    }

    private fun handleBroadcastUsers(
        context: Context,
        snapshot: QuerySnapshot,
        titleResId: Int,
        bodyResId: Int,
        bodyFormatArgs: List<String>
    ) {
        val users = collectUsersWithSubscription(snapshot)
        Log.d(TAG_BROADCAST, "Firestore: ${snapshot.size()} docs, ${users.size} con onesignal_id válido.")
        if (users.isEmpty()) {
            Log.e(TAG_BROADCAST, "❌ Ningún usuario tiene onesignal_id. Verifica linkDeviceWithUser().")
            return
        }
        CoroutineScope(ioDispatcher).launch {
            executeBroadcast(context, users, titleResId, bodyResId, bodyFormatArgs)
        }
    }

    private fun collectUsersWithSubscription(snapshot: QuerySnapshot): List<UserEntry> =
        snapshot.documents.mapNotNull { doc ->
            val id = doc.getString("onesignal_id")
            if (id.isNullOrBlank()) null
            else UserEntry(
                userId       = doc.id,
                onesignalId  = id,
                languageCode = doc.getString("language") ?: "en"
            )
        }

    private fun executeBroadcast(
        context: Context,
        users: List<UserEntry>,
        titleResId: Int,
        bodyResId: Int,
        bodyFormatArgs: List<String>
    ) {
        val appId   = resolveResString(context, "onesignal_app_id_secret")
        val restKey = resolveResString(context, "onesignal_rest_api_key_secret")
        if (!validateBroadcastCredentials(appId, restKey)) return

        val (headings, contents) = buildMultiLanguagePayload(context, titleResId, bodyResId, bodyFormatArgs)
        val succeeded = sendAllChunks(users.map { it.onesignalId }, appId, headings, contents, restKey)
        if (succeeded) persistNotificationsToFirestore(context, users, titleResId, bodyResId, bodyFormatArgs)
    }

    private fun validateBroadcastCredentials(appId: String, restKey: String): Boolean {
        if (appId.isEmpty()) { Log.e(TAG_BROADCAST, "❌ App ID vacío — broadcast cancelado."); return false }
        if (restKey.isEmpty()) Log.e(TAG_BROADCAST, "❌ REST API Key vacía — el servidor rechazará la petición.")
        return true
    }

    /** Builds OneSignal headings/contents JSONObjects with all supported translations. */
    private fun buildMultiLanguagePayload(
        context: Context,
        titleResId: Int,
        bodyResId: Int,
        bodyFormatArgs: List<String>
    ): Pair<JSONObject, JSONObject> {
        val headings = JSONObject()
        val contents = JSONObject()
        SUPPORTED_LOCALES.forEach { code ->
            headings.put(code, resolveLocalizedString(context, code, titleResId, emptyList()))
            contents.put(code, resolveLocalizedString(context, code, bodyResId, bodyFormatArgs))
        }
        return headings to contents
    }

    /**
     * Resolves [resId] in the given [localeCode], optionally substituting [args].
     * ISO-8601 date strings in [args] are reformatted in [localeCode]'s locale.
     */
    private fun resolveLocalizedString(
        context: Context,
        localeCode: String,
        resId: Int,
        args: List<String>
    ): String {
        val locale = Locale.forLanguageTag(localeCode)
        val config = Configuration(context.resources.configuration)
        config.setLocale(locale)
        val ctx          = context.createConfigurationContext(config)
        val resolvedArgs = args.map { formatArgForLocale(it, locale) }.toTypedArray()
        return if (resolvedArgs.isEmpty()) ctx.getString(resId) else ctx.getString(resId, *resolvedArgs)
    }

    /** If [arg] is an ISO-8601 date ("yyyy-MM-dd"), returns it formatted for [locale]. */
    private fun formatArgForLocale(arg: String, locale: Locale): String {
        if (!ISO_DATE_PATTERN.matches(arg)) return arg
        return try {
            val raw = SimpleDateFormat("yyyy-MM-dd", Locale.US).parse(arg)
            if (raw != null) SimpleDateFormat("EEEE, MMM d", locale).format(raw) else arg
        } catch (e: Exception) { arg }
    }

    private fun sendAllChunks(
        ids: List<String>,
        appId: String,
        headings: JSONObject,
        contents: JSONObject,
        restKey: String
    ): Boolean {
        var atLeastOneSucceeded = false
        ids.chunked(2_000).forEachIndexed { index, chunk ->
            try {
                val code = postToOneSignal(buildPushPayload(appId, chunk, headings, contents), restKey)
                Log.d(TAG_BROADCAST, "Chunk $index → HTTP $code")
                if (code in 200..299) { atLeastOneSucceeded = true; Log.d(TAG_BROADCAST, "✅ Chunk $index OK.") }
                else Log.e(TAG_BROADCAST, "❌ Chunk $index rechazado (HTTP $code).")
            } catch (e: Exception) { Log.e(TAG_BROADCAST, "Error en chunk $index", e) }
        }
        return atLeastOneSucceeded
    }

    private fun buildPushPayload(appId: String, ids: List<String>, headings: JSONObject, contents: JSONObject) =
        JSONObject().apply {
            put("app_id", appId)
            put("include_subscription_ids", JSONArray().apply { ids.forEach { put(it) } })
            put("headings", headings)
            put("contents", contents)
            put("android_sound", "notification")
            put("priority", 10)
        }

    /** Saves a [NotificationItem] per user, translated into the user's stored language. */
    private fun persistNotificationsToFirestore(
        context: Context,
        users: List<UserEntry>,
        titleResId: Int,
        bodyResId: Int,
        bodyFormatArgs: List<String>
    ) {
        users.forEach { user ->
            val localTitle = resolveLocalizedString(context, user.languageCode, titleResId, emptyList())
            val localBody  = resolveLocalizedString(context, user.languageCode, bodyResId, bodyFormatArgs)
            saveNotification(NotificationItem(userId = user.userId, title = localTitle, body = localBody, isRead = false))
        }
        Log.d(TAG_BROADCAST, "✅ NotificationItem guardado para ${users.size} usuarios.")
    }

    // ── HTTP helper ───────────────────────────────────────────────────────────

    private fun resolveResString(context: Context, resName: String): String {
        val id = context.resources.getIdentifier(resName, "string", context.packageName)
        return if (id != 0) context.getString(id) else ""
    }

    private fun postToOneSignal(body: JSONObject, restApiKey: String): Int {
        val conn = URL("https://onesignal.com/api/v1/notifications").openConnection() as HttpURLConnection
        return try {
            conn.requestMethod = "POST"
            conn.setRequestProperty("Content-Type", "application/json; charset=UTF-8")
            if (restApiKey.isNotEmpty()) conn.setRequestProperty("Authorization", "Basic $restApiKey")
            conn.doOutput = true
            OutputStreamWriter(conn.outputStream).use { it.write(body.toString()); it.flush() }
            val code = conn.responseCode
            if (code !in 200..299) {
                val err = BufferedReader(InputStreamReader(conn.errorStream ?: conn.inputStream)).use { it.readText() }
                Log.e(TAG_HTTP, "HTTP $code: $err")
            }
            code
        } finally { conn.disconnect() }
    }

    companion object {
        private const val TAG_BROADCAST = "OneSignal_Broadcast"
        private const val TAG_PUSH      = "OneSignal_Push"
        private const val TAG_FIRESTORE = "OneSignal_Firestore"
        private const val TAG_HTTP      = "OneSignal_HTTP"
    }
}

package com.lksnext.ParkingMMartinez.ui.screens

import androidx.compose.foundation.BorderStroke
import androidx.compose.foundation.background
import androidx.compose.foundation.horizontalScroll
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.foundation.verticalScroll
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.AccessTime
import androidx.compose.material3.*
import androidx.compose.runtime.Composable
import androidx.compose.runtime.rememberCoroutineScope
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.testTag
import androidx.compose.ui.res.stringResource
import androidx.compose.ui.unit.dp
import androidx.lifecycle.viewmodel.compose.viewModel
import com.lksnext.ParkingMMartinez.R
import com.lksnext.ParkingMMartinez.ui.components.DateItem
import com.lksnext.ParkingMMartinez.ui.components.LksHeader
import com.lksnext.ParkingMMartinez.ui.components.LksTimePicker
import com.lksnext.ParkingMMartinez.ui.components.ZoneCard
import com.lksnext.ParkingMMartinez.ui.theme.bookingCardColor
import com.lksnext.ParkingMMartinez.ui.theme.lightGray
import com.lksnext.ParkingMMartinez.ui.theme.mistGray
import com.lksnext.ParkingMMartinez.ui.viewmodel.MapViewModel
import androidx.lifecycle.compose.LifecycleResumeEffect
import com.lksnext.ParkingMMartinez.ui.viewmodel.BookingViewModel
import com.lksnext.ParkingMMartinez.ui.constants.TestTags
import kotlinx.coroutines.launch
import kotlinx.coroutines.delay
import java.util.Calendar

@Composable
fun MapScreen(
    viewModel: MapViewModel = viewModel(),
    bookingViewModel: BookingViewModel,
    onZoneClick: (String) -> Unit
) {
    val scope = rememberCoroutineScope()

    LifecycleResumeEffect(Unit) {
        bookingViewModel.cancelEditing()
        bookingViewModel.checkUserReservationStatus()

        //Metodo manual, ya que no disponemos de los servicios cloud de firebase
        val job = scope.launch {
            while (true) {
                viewModel.refreshParking()
                delay(30_000L)
            }
        }

        onPauseOrDispose {
            job.cancel()
        }
    }

    if (viewModel.showTimePicker) {
        LksTimePicker(
            onConfirm = { h, m ->
                viewModel.onTimeChange(h, m)
                viewModel.showTimePicker = false
            },
            onDismiss = { viewModel.showTimePicker = false },
            modifier = Modifier.testTag(TestTags.TIME_PICKER_DIALOG),
            confirmButtonModifier = Modifier.testTag(TestTags.TIME_PICKER_CONFIRM),
            dismissButtonModifier = Modifier.testTag(TestTags.TIME_PICKER_CANCEL)
        )
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(mistGray)
    ) {
        LksHeader(
            title = stringResource(R.string.map_header_title),
            subtitle = stringResource(R.string.map_header_subtitle),
            modifier = Modifier.testTag(TestTags.MAP_HEADER)
        )

        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(horizontal = 16.dp)
                .verticalScroll(rememberScrollState()),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            Spacer(Modifier.height(4.dp))

            // --- SELECTOR DE FECHAS HORIZONTAL ---
            DateSelectorSection(viewModel)

            // --- SELECTOR DE HORA DE INICIO ---
            TimeSelectorSection(viewModel)

            // --- ZONAS DE APARCAMIENTO ---
            ParkingZonesSection(viewModel, bookingViewModel, onZoneClick)
        }
    }
}

@Composable
private fun DateSelectorSection(viewModel: MapViewModel) {
    val todayStr = stringResource(R.string.booking_today)

    Row(
        modifier = Modifier
            .fillMaxWidth()
            .horizontalScroll(rememberScrollState()),
        horizontalArrangement = Arrangement.spacedBy(10.dp)
    ) {
        viewModel.availableDates.forEach { (fullDate, label) ->
            val displayLabel = if (label == "TODAY") todayStr else {
                val sdf = java.text.SimpleDateFormat("EEE", java.util.Locale.getDefault())

                sdf.format(fullDate).replaceFirstChar { it.uppercase() }
            }

            val cal = Calendar.getInstance().apply { time = fullDate }
            val dayNumStr = cal.get(Calendar.DAY_OF_MONTH).toString()

            DateItem(
                day = dayNumStr,
                label = displayLabel,
                isSelected = viewModel.selectedDate == fullDate,
                modifier = Modifier.testTag("${TestTags.MAP_DATE_ITEM_PREFIX}$dayNumStr"),
                onClick = { viewModel.onDateSelected(fullDate) }
            )
        }
    }
}

@Composable
private fun TimeSelectorSection(viewModel: MapViewModel) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(containerColor = Color.White),
        border = BorderStroke(1.dp, Color.LightGray),
        shape = RoundedCornerShape(16.dp)
    ) {
        Column(modifier = Modifier.padding(14.dp)) {
            Text(
                text = stringResource(R.string.booking_start_time),
                style = MaterialTheme.typography.labelSmall,
                color = Color.Gray
            )

            OutlinedCard(
                onClick = { viewModel.showTimePicker = true },
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(top = 8.dp)
                    .testTag(TestTags.MAP_TIME_PICKER_TRIGGER),
                shape = RoundedCornerShape(12.dp),
                colors = CardDefaults.outlinedCardColors(containerColor = bookingCardColor),
                border = BorderStroke(1.dp, lightGray)
            ) {
                Row(
                    modifier = Modifier.padding(12.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    Text(
                        text = java.lang.String.format("%02d:%02d", viewModel.selectedStartTime.hour, viewModel.selectedStartTime.minute),
                        style = MaterialTheme.typography.titleMedium
                    )
                    Icon(Icons.Default.AccessTime, null, tint = Color.Gray)
                }
            }
        }
    }
}

@Composable
private fun ParkingZonesSection(
    viewModel: MapViewModel,
    bookingViewModel: BookingViewModel,
    onZoneClick: (String) -> Unit
) {
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .padding(bottom = 16.dp),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        viewModel.zones.forEach { zone ->
            val isZoneFull = zone.availableSpots <= 0

            ZoneCard(
                zone = zone,
                modifier = Modifier.testTag("${TestTags.MAP_ZONE_CARD_PREFIX}${zone.name}"),
                onClick = {
                    if (!isZoneFull) {
                        bookingViewModel.onDateSelected(viewModel.selectedDate)
                        onZoneClick(zone.name)
                    }
                }
            )
        }
    }
}

